module RefModule(
    input clk,
    input rst,
    input up,
    input down,
    output reg [2:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk) begin
    if (rst) begin
        count <= 3'b000;
    end else if (up && !down) begin
        count <= count + 1;
    end else if (!up && down) begin
        count <= count - 1;
    end
end

endmodule
